if (
  node.kind < ts.SyntaxKind.FirstNode ||
  node.kind > ts.SyntaxKind.FirstJSDocNode
) {
  return;
}

return (
  node.attributes.some(({ name }) => isAlt(name)) ||
  node.inputs.some(({ name }) => isAlt(name))
);

return (
  input.sourceSpan.start === output.sourceSpan.start &&
  input.sourceSpan.end === output.sourceSpan.end
);

if (attr.name.startsWith('#')) {
  return {
    name: attr.name.slice(1),
    orderType: OrderType.TemplateReferenceVariable,
  };
}

const legacyStructuralDirectiveRegex = isModified
        ? /^(ngForOf|ngIf|ngSwitch)$/
        : /^(ngForOf|ngIf|ngSwitchCase)$/;

if (
  i18n ||
  !checkAttributes ||
  isAttributeAllowed(allowedAttributes, elementName, attributeName, value)
) {
  return;
}

const DEFAULT_LABEL_COMPONENTS: readonly LabelComponent[] = [
  { inputs: ['for', 'htmlFor'], selector: 'label' },
];

const allControlComponents: ReadonlySet<string> = new Set([
  ...DEFAULT_CONTROL_COMPONENTS,
  ...(controlComponents ?? []),
]);

const eventPairs = [
      [KeyEvents.Blur, MouseEvents.MouseOut],
      [KeyEvents.Focus, MouseEvents.MouseOver],
    ] as const;

return (
  allowList &&
  allowList.length > 0 &&
  isASTWithName(ast) &&
  allowList.indexOf(ast.name) > -1
);

return (
  !!contentEnd &&
  context.sourceCode.text
    .slice(contentStart.offset, contentEnd.offset)
    .trim() === ''
);

return (
  node.attributes.some(({ name }) => isStyle(name)) ||
  node.inputs.some(({ name }) => isStyle(name))
);

return children.some(
  (child) =>
    child instanceof TmplAstElement &&
    (child.name === childNodeName || traverseChildNodes(child)),
);

if (ASTUtils.isTemplateLiteral(node)) {
  return node.quasis[0].value.raw.trim().split(NEW_LINE_REGEXP).length;
}

return (
  value !== null &&
  typeof value === 'object' &&
  'type' in value &&
  typeof (value as { type: unknown }).type === 'string'
);

return {
  [Selectors.OUTPUT_DECORATOR]: (node) => {
    context.report({ node, messageId: 'preferOutputEmitterRef' });
  },
};

if (ASTUtils.isTemplateLiteral(node)) {
  return !RELATIVE_URL_PREFIX_MATCHER.test(node.quasis[0].value.raw);
}

const DEFAULT_OPTIONS: Options[number] = {
  requireDescription: false,
  requireMeaning: false,
  requireCustomId: false,
};

generateFiles(
  tree,
  path.join(__dirname, 'files/tests'),
  `${baseTarget}/tests/rules/${ruleName}`,
  options,
);

if (
  !rules ||
  !rules['@angular-eslint/template/no-negated-async'] ||
  rules['@angular-eslint/template/eqeqeq']
) {
  return;
}

return Object.keys(obj)
    .sort()
    .reduce((result, key) => {
      return {
        ...result,
        [key]: obj[key],
      };
    }, {});

return (
  node !== null &&
  typeof node === 'object' &&
  typeof (node as { type?: unknown }).type === 'string'
);

return {
  start: { line: startLine + 1, column: startColumn },
  end: { line: endLine + 1, column: endColumn },
};

if (
  isPropertyDefinition(node) ||
  isMethodDefinition(node) ||
  isProperty(node)
) {
  return getRawText(node.key);
}

export const isNotNullOrUndefined = <T>(
  input: null | undefined | T,
): input is T => input !== null && input !== undefined;

if (
  settings.filterRequiresTypeChecking === 'exclude' &&
  value.meta.docs?.requiresTypeChecking === true
) {
  return config;
}

if (
  settings.filterRequiresTypeChecking === 'include' &&
  value.meta.docs?.requiresTypeChecking !== true
) {
  return config;
}
